SELECT COUNT(observation_id) 
FROM observations 
WHERE location_id = 1;

SELECT * 
FROM observations 
WHERE magnitude = (SELECT MAX(magnitude) FROM observations);

SELECT observations.observation_id, organizations.organization_name
FROM observations
JOIN organizations ON observations.organization_id = organizations.organization_id;

SELECT observations.observation_id
FROM observations
JOIN locations ON observations.location_id = locations.location_id;

SELECT organization_name, contact_email 
FROM organizations 
WHERE organization_id IN (SELECT DISTINCT organization_id FROM observations);

SELECT observation_id
FROM observations
WHERE magnitude > 10 AND duration = 'long';
